// { Greedy insertion that evaluates every existing assign, selecting the one with the smallest cost increase for each order; if none feasible, a new assign is created. }
for jj := range oris {
	bestDelta := 1e18
	bestIdx := -1

	// Evaluate insertion into every existing assign
	for i := 0; i < dispatch.AssignsLen; i++ {
		// remember original cost (0 if the route is empty)
		origCost := dispatch.Assigns[i].Cost

		if !dispatch.Assigns[i].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			continue
		}
		dispatch.Assigns[i].GenRoute()
		newCost := dispatch.Assigns[i].Cost
		if newCost >= 0 {
			delta := newCost - origCost
			if delta < bestDelta {
				bestDelta = delta
				bestIdx = i
			}
		}
		// undo the trial insertion
		dispatch.Assigns[i].RemoveShip(total_ship + jj)
		dispatch.Assigns[i].GenRoute()
	}

	if bestIdx != -1 {
		// apply the best insertion permanently
		dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
		dispatch.Assigns[bestIdx].GenRoute()
	} else {
		// fallback: start a new assign
		if dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			if dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[newIdx].GenRoute()
					// extremely rare: even an empty assign fails; leave it as is and continue
				}
			}
		} else {
			// no free assign slot; safely try the first assign as a last-hope seed
			if dispatch.Assigns[0].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[0].GenRoute()
				if dispatch.Assigns[0].Cost < 0 {
					dispatch.Assigns[0].RemoveShip(total_ship + jj)
					dispatch.Assigns[0].GenRoute()
				}
			}
		}
	}
}
dispatch.RenewnTotalCost()
return dispatch

