func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

population.algorithm:
Cheapest-insertion heuristic with a penalty on route length: minimizes costIncrease + 0.1*directDistance*newStationCount, where directDistance is the direct travel cost between origin and destination.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for j := range oris {
		shipID := total_ship + j
		ori := oris[j]
		des := dess[j]

		direct := cal_dis(ori, des)
		penaltyFactor := 0.1 * direct

		bestScore := 1e18
		bestIdx := -1

		// Evaluate insertion into every existing non-empty assign
		for i := 0; i < dispatch.AssignsLen; i++ {
			a := &dispatch.Assigns[i]
			if a.StationsLen == 0 {
				continue
			}
			oldCost := a.Cost
			oldStations := a.StationsLen

			ok := a.AddShip(shipID, ori, des)
			if !ok {
				a.Cost = -1
			} else {
				a.GenRoute()
			}
			newCost := a.Cost
			newStations := a.StationsLen

			// Revert
			a.RemoveShip(shipID)
			a.GenRoute()

			if newCost >= 0 {
				diff := newCost - oldCost
				score := diff + penaltyFactor*float64(newStations)
				// Prefer shorter routes; if newStations equals oldStations+1 we can still use it
				_ = oldStations
				if score < bestScore {
					bestScore = score
					bestIdx = i
				}
			}
		}

		// Evaluate insertion into a potential new empty assign
		if dispatch.AssignsLen < MAXASSIGNS {
			i := dispatch.AssignsLen
			a := &dispatch.Assigns[i]
			ok := a.AddShip(shipID, ori, des)
			if !ok {
				a.Cost = -1
			} else {
				a.GenRoute()
			}
			newCost := a.Cost
			newStations := a.StationsLen
			a.RemoveShip(shipID)
			a.GenRoute()

			if newCost >= 0 {
				score := newCost + penaltyFactor*float64(newStations) // oldCost is 0, diff = newCost
				if score < bestScore {
					bestScore = score
					bestIdx = i
				}
			}
		}

		if bestIdx != -1 {
			// Apply best insertion
			a := &dispatch.Assigns[bestIdx]
			a.AddShip(shipID, ori, des)
			a.GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			// Safe fallback: insert into a new direct assignment
			if dispatch.AssignsLen < MAXASSIGNS {
				a := &dispatch.Assigns[dispatch.AssignsLen]
				if !a.AddShip(shipID, ori, des) {
					a.Cost = -1
				}
				a.GenRoute()
				dispatch.AssignsLen++
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

