// {Greedy best-insertion with cost delta minimization: for each order, evaluate all existing vehicles and one new vehicle, then permanently apply the insertion that yields the smallest increase in vehicle cost; if none feasible, fall back with a new vehicle.}
for jj := range oris {
	bestDelta := 1e18
	bestIdx := -1

	// Evaluate all existing assigns (including empty ones that already have a current position)
	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		origCost := dispatch.Assigns[ii].Cost
		ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
		if !ok {
			dispatch.Assigns[ii].Cost = -1
		} else {
			dispatch.Assigns[ii].GenRoute()
		}
		if dispatch.Assigns[ii].Cost >= 0 {
			delta := dispatch.Assigns[ii].Cost - origCost
			if delta < bestDelta {
				bestDelta = delta
				bestIdx = ii
			}
		}
		// Revert evaluation
		dispatch.Assigns[ii].RemoveShip(total_ship + jj)
		dispatch.Assigns[ii].GenRoute()
	}

	// Evaluate a potential brand‑new vehicle
	if dispatch.AssignsLen < MAXASSIGNS {
		ii := dispatch.AssignsLen
		origCost := 0.0 // empty vehicle cost is zero
		ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
		if !ok {
			dispatch.Assigns[ii].Cost = -1
		} else {
			dispatch.Assigns[ii].GenRoute()
		}
		if dispatch.Assigns[ii].Cost >= 0 {
			delta := dispatch.Assigns[ii].Cost - origCost
			if delta < bestDelta {
				bestDelta = delta
				bestIdx = ii // marks the new vehicle slot
			}
		}
		// Revert evaluation
		dispatch.Assigns[ii].RemoveShip(total_ship + jj)
		dispatch.Assigns[ii].GenRoute()
	}

	// Apply the best insertion found
	if bestIdx >= 0 {
		if bestIdx == dispatch.AssignsLen {
			// The new vehicle was the best choice
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			dispatch.AssignsLen++
		} else {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		}
	} else {
		// Fallback safe seed insertion: force a new vehicle
		if dispatch.AssignsLen < MAXASSIGNS {
			dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[dispatch.AssignsLen].GenRoute()
			dispatch.AssignsLen++
		}
		// If no vehicle slot remains the order cannot be placed, but we continue processing the rest
	}
}

